        return new Source("{% extends 'base.html.twig' %}

{% block title %}Reclamation index{% endblock %}

{% block body %}
    <h1>Reclamation index</h1>

    <table class=\"table\">
        <thead>
            <tr>
                <th>Id</th>
                <th>Nomrec</th>
                <th>Adressmail</th>
                <th>Sujetrec</th>
                <th>Date_creation</th>
                <th>Etat</th>
                <th>Descriptionrec</th>
                <th>actions</th>
            </tr>
        </thead>
        <tbody>
        {% for reclamation in reclamations %}
            <tr>
                <td>{{ reclamation.id }}</td>
                <td>{{ reclamation.nomrec }}</td>
                <td>{{ reclamation.adressmail }}</td>
                <td>{{ reclamation.sujetrec }}</td>
                <td>{{ reclamation.dateCreation ? reclamation.dateCreation|date('Y-m-d H:i:s') : '' }}</td>
                <td>{{ reclamation.etat }}</td>
                <td>{{ reclamation.descriptionrec }}</td>
                <td>
                    <a href=\"{{ path('app_reclamation_show', {'id': reclamation.id}) }}\">show</a>
                    <a href=\"{{ path('app_reclamation_edit', {'id': reclamation.id}) }}\">edit</a>
                </td>
            </tr>
        {% else %}
            <tr>
                <td colspan=\"8\">no records found</td>
            </tr>
        {% endfor %}
        </tbody>
    </table>

    <a href=\"{{ path('app_reclamation_new') }}\">Create new</a>
{% endblock %}
